Why is this inferred RAM throwing a "multi-driven net" error when doing a read-modify-write operation?
module dual_port_ram (input clk, input [7:0] addr, input [15:0] din, input we, output reg [15:0] dout);
  reg [15:0] ram [0:255];
  always @(posedge clk) begin
    if (we) ram[addr] <= din;
  end
  always @(posedge clk) begin
    dout <= ram[addr];
  end
endmodule
